import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const denyTest = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'deny test',
    parameters: {
      mode: 'passthrough'
    }
  }
});

export default workflow('manual-deny-test', 'Manual Trigger - Deny Test')
  .add(manualTrigger)
  .to(denyTest);
